		public static bool CheckFormulaExist(string sFieldNameChecked, FormulaFieldDefinitions oFormulaFields)
		{
			//IL_0011: Unknown result type (might be due to invalid IL or missing references)
			//IL_0017: Expected O, but got Unknown
			foreach (FormulaFieldDefinition item in (SCRCollection)oFormulaFields)
			{
				FormulaFieldDefinition val = item;
				if (((FieldDefinition)val).Name.ToUpper().Equals(sFieldNameChecked.ToUpper()))
				{
					return true;
				}
			}
			return false;
		}

