		public static void FormatChartControl(ctlReportChart ctl, ReportChartInfo chartInfo)
		{
			FieldInfo[] fields = chartInfo.GetType().GetFields(BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
			FieldInfo[] array = fields;
			foreach (FieldInfo fieldInfo in array)
			{
				((object)ctl).GetType().GetProperty(fieldInfo.Name.Substring(1))?.SetValue(ctl, RuntimeHelpers.GetObjectValue(fieldInfo.GetValue(chartInfo)), null);
			}
		}

