		public static string DOI_SO_CHU_vi_VN(double dblSo, string strDVT = "đồng")
		{
			string[] array = new string[10] { "không", "một", "hai", "ba", "bốn", "năm", "sáu", "bảy", "tám", "chín" };
			string text = "";
			string text2 = "";
			string text3 = "";
			string text4 = "";
			string text5 = "";
			string text6 = "";
			if (dblSo < 0.0)
			{
				dblSo = 0.0 - dblSo;
				text2 += " âm";
			}
			decimal d = new decimal(dblSo - Conversion.Int(dblSo));
			if (Conversion.Int(dblSo) == 0.0)
			{
				text2 = "không0";
			}
			else
			{
				text3 = Strings.Trim(Conversion.Str((object)Conversion.Int(dblSo)));
				if (text3.Trim().Length % 3 == 1)
				{
					text3 = "00" + text3.Trim();
				}
				if (text3.Trim().Length % 3 == 2)
				{
					text3 = "0" + text3.Trim();
				}
				checked
				{
					int num = (int)Math.Round((double)text3.Trim().Length / 3.0);
					int num2 = num;
					while (true)
					{
						int num3 = num2;
						int num4 = 1;
						if (num3 < num4)
						{
							break;
						}
						text6 = text3.Trim().Substring(text3.Trim().Length - num2 * 3, 3);
						text2 = ((DOI_SO_CHU_NHOM_Vi_VN(text6, num2, num).Trim().Length <= 0) ? (text2 + " " + DOI_SO_CHU_NHOM_Vi_VN(text6, num2, num).Trim()) : ((num2 >= 5) ? (text2 + " " + DOI_SO_CHU_NHOM_Vi_VN(text6, num2, num).Trim()) : (text2 + " " + DOI_SO_CHU_NHOM_Vi_VN(text6, num2, num).Trim() + ",")));
						num2 += -1;
					}
				}
			}
			text2 = text2.Trim();
			checked
			{
				text2 = Strings.Left(text2, text2.Length - 1);
				if (decimal.Compare(d, 0m) > 0)
				{
					text4 = d.ToString("0.######").Trim();
					text4 = text4.Substring(2, text4.Length - 2);
					while (Operators.CompareString(Strings.Right(text4, 1), "0", false) == 0)
					{
						text4 = Strings.Left(text4, text4.Length - 1);
					}
					if (Operators.CompareString(text4.Substring(0, 1), "0", false) != 0)
					{
						unchecked
						{
							if (text4.Trim().Length % 3 == 1)
							{
								text4 = "00" + text4.Trim();
							}
							if (text4.Trim().Length % 3 == 2)
							{
								text4 = "0" + text4.Trim();
							}
						}
						int num = (int)Math.Round((double)text4.Trim().Length / 3.0);
						int num2 = num;
						while (true)
						{
							int num5 = num2;
							int num4 = 1;
							if (num5 >= num4)
							{
								text6 = text4.Trim().Substring(text4.Trim().Length - num2 * 3, 3);
								text5 = text5 + " " + DOI_SO_CHU_NHOM_Vi_VN(text6, num2, num).Trim();
								num2 += -1;
								continue;
							}
							break;
						}
					}
					else
					{
						int num6 = text4.Length - 1;
						int num7 = 0;
						while (true)
						{
							int num8 = num7;
							int num4 = num6;
							if (num8 > num4)
							{
								break;
							}
							char c = Conversions.ToChar(text4.Substring(num7, 1));
							text5 = text5 + " " + array[Conversion.Val(c)].Trim();
							num7++;
						}
					}
					text = text2.Trim() + " phẩy " + text5.Trim() + " " + strDVT.Trim();
				}
				else
				{
					text = text2.Trim() + " " + strDVT.Trim();
				}
				text.Trim();
				return Strings.Left(text, 1).ToUpper() + Strings.Right(text, text.Length - 1);
			}
		}

		public static object SpellMoneyNumber(object sNumber, string sMa_Nt, string MUnit = "dollar", string SUnit = "cent")
		{
			if (!Versioned.IsNumeric(RuntimeHelpers.GetObjectValue(sNumber)))
			{
				return "";
			}
			string[] array = new string[10];
			bool flag = Conversions.ToBoolean(Interaction.IIf(Operators.CompareString(sMa_Nt, Environment.GetSIConfiguration().ma_nt0, false) == 0, (object)false, (object)true));
			object obj = "";
			object obj2 = "";
			array[2] = " thousand ";
			array[3] = " million ";
			array[4] = " billion ";
			array[5] = " trillion ";
			sNumber = Strings.Trim(Conversion.Str(RuntimeHelpers.GetObjectValue(sNumber)));
			object obj3 = Strings.InStr(Conversions.ToString(sNumber), ".", (CompareMethod)0);
			if (Operators.ConditionalCompareObjectGreater(obj3, (object)0, false))
			{
				obj2 = ReadTens(Strings.Left(Strings.Mid(Conversions.ToString(sNumber), Conversions.ToInteger(Operators.AddObject(obj3, (object)1))) + "00", 2));
				sNumber = Strings.Trim(Strings.Left(Conversions.ToString(sNumber), Conversions.ToInteger(Operators.SubtractObject(obj3, (object)1))));
			}
			object obj4 = 1;
			while (Operators.ConditionalCompareObjectNotEqual(sNumber, (object)"", false))
			{
				object obj5 = ReadHundreds(Strings.Right(Conversions.ToString(sNumber), 3));
				if (Operators.ConditionalCompareObjectNotEqual(obj5, (object)"", false))
				{
					obj = Operators.ConcatenateObject(Operators.ConcatenateObject(obj5, (object)array[Conversions.ToInteger(obj4)]), obj);
				}
				sNumber = ((Strings.Len(RuntimeHelpers.GetObjectValue(sNumber)) <= 3) ? "" : Strings.Left(Conversions.ToString(sNumber), checked(Strings.Len(RuntimeHelpers.GetObjectValue(sNumber)) - 3)));
				obj4 = Operators.AddObject(obj4, (object)1);
			}
			object obj6 = obj;
			obj = (Conversions.ToBoolean((Conversions.ToBoolean(Operators.CompareObjectEqual(obj6, (object)"", false)) || Conversions.ToBoolean(Operators.CompareObjectEqual(obj6, (object)"0", false))) ? ((object)true) : ((object)false)) ? Operators.ConcatenateObject((object)("no " + MUnit), Interaction.IIf(flag, (object)"s", (object)"")) : ((!Conversions.ToBoolean((Conversions.ToBoolean(Operators.CompareObjectEqual(obj6, (object)"One", false)) || Conversions.ToBoolean(Operators.CompareObjectEqual(obj6, (object)"one", false))) ? ((object)true) : ((object)false))) ? Operators.ConcatenateObject(Operators.ConcatenateObject(Operators.ConcatenateObject(NewLateBinding.LateGet(obj, (Type)null, "Trim", new object[0], (string[])null, (Type[])null, (bool[])null), (object)" "), (object)MUnit), Interaction.IIf(flag, (object)"s", (object)"")) : ("one " + MUnit)));
			object obj7 = obj2;
			obj2 = (Operators.ConditionalCompareObjectEqual(obj7, (object)"", false) ? "" : ((!Operators.ConditionalCompareObjectEqual(obj7, (object)"one", false)) ? Operators.ConcatenateObject(Operators.ConcatenateObject(Operators.ConcatenateObject(Operators.ConcatenateObject((object)" and ", obj2), (object)" "), (object)SUnit), (object)"s") : (" and one " + SUnit)));
			obj = Strings.Left(Conversions.ToString(obj), 1).ToUpper() + Strings.Right(Conversions.ToString(obj), Conversions.ToInteger(Operators.SubtractObject(NewLateBinding.LateGet(obj, (Type)null, "Length", new object[0], (string[])null, (Type[])null, (bool[])null), (object)1)));
			return Operators.ConcatenateObject(obj, obj2);
		}

		public static string ReadHundreds(object sNumber)
		{
			string text = "";
			if (Conversion.Val(RuntimeHelpers.GetObjectValue(sNumber)) == 0.0)
			{
				return "";
			}
			sNumber = Strings.Right(Conversions.ToString(Operators.ConcatenateObject((object)"000", sNumber)), 3);
			if (Operators.CompareString(Strings.Mid(Conversions.ToString(sNumber), 1, 1), "0", false) != 0)
			{
				text = ReadDigit(Strings.Mid(Conversions.ToString(sNumber), 1, 1)) + " hundred ";
			}
			return (Operators.CompareString(Strings.Mid(Conversions.ToString(sNumber), 2, 1), "0", false) == 0) ? (text + ReadDigit(Strings.Mid(Conversions.ToString(sNumber), 3))) : (text + ReadTens(Strings.Mid(Conversions.ToString(sNumber), 2)));
		}

		public static string ReadTens(string TensText)
		{
			string text = "";
			if (Conversion.Val(Strings.Left(TensText, 1)) == 1.0)
			{
				double num = Conversion.Val(TensText);
				if (num == 10.0)
				{
					text = "ten";
				}
				else if (num == 11.0)
				{
					text = "eleven";
				}
				else if (num == 12.0)
				{
					text = "twelve";
				}
				else if (num == 13.0)
				{
					text = "thirteen";
				}
				else if (num == 14.0)
				{
					text = "fourteen";
				}
				else if (num == 15.0)
				{
					text = "fifteen";
				}
				else if (num == 16.0)
				{
					text = "sixteen";
				}
				else if (num == 17.0)
				{
					text = "seventeen";
				}
				else if (num == 18.0)
				{
					text = "eighteen";
				}
				else if (num == 19.0)
				{
					text = "nineteen";
				}
			}
			else
			{
				double num2 = Conversion.Val(Strings.Left(TensText, 1));
				if (num2 == 2.0)
				{
					text = "twenty ";
				}
				else if (num2 == 3.0)
				{
					text = "thirty ";
				}
				else if (num2 == 4.0)
				{
					text = "forty ";
				}
				else if (num2 == 5.0)
				{
					text = "fifty ";
				}
				else if (num2 == 6.0)
				{
					text = "sixty ";
				}
				else if (num2 == 7.0)
				{
					text = "seventy ";
				}
				else if (num2 == 8.0)
				{
					text = "eighty ";
				}
				else if (num2 == 9.0)
				{
					text = "ninety ";
				}
				text += ReadDigit(Strings.Right(TensText, 1));
			}
			return text;
		}

