		public static System.Data.DataTable GroupBy(string i_sGroupByColumn, string i_sAggregateColumn, System.Data.DataTable i_dSourceTable)
		{
			DataView dataView = new DataView(i_dSourceTable);
			System.Data.DataTable dataTable = dataView.ToTable(true, i_sGroupByColumn);
			dataTable.Columns.Add("Count", typeof(int));
			foreach (DataRow row in dataTable.Rows)
			{
				row["Count"] = RuntimeHelpers.GetObjectValue(i_dSourceTable.Compute("Count(" + i_sAggregateColumn + ")", Conversions.ToString(Operators.ConcatenateObject(Operators.ConcatenateObject((object)(i_sGroupByColumn + " = '"), row[i_sGroupByColumn]), (object)"'"))));
			}
			return dataTable;
		}

		public static System.Data.DataTable ComputeWithGroupBy(System.Data.DataTable sourceTable, string colList, string aggregateColList, string filter = "")
		{
			System.Data.DataTable result;
			try
			{
				DataView dataView = new DataView(sourceTable, filter, colList, DataViewRowState.CurrentRows);
				System.Data.DataTable dataTable = dataView.ToTable(true, colList);
				string[] array = aggregateColList.Split(new char[1] { ',' });
				foreach (string columnName in array)
				{
					dataTable.Columns.Add(columnName, typeof(double));
				}
				foreach (DataRow row in dataTable.Rows)
				{
					string[] array2 = aggregateColList.Split(new char[1] { ',' });
					foreach (string text in array2)
					{
						row[text] = RuntimeHelpers.GetObjectValue(sourceTable.Compute(text, filter));
					}
				}
				result = dataTable;
			}
			catch (Exception ex)
			{
				ProjectData.SetProjectError(ex);
				Exception ex2 = ex;
				Helper.ProcessError(ex2);
				result = null;
				ProjectData.ClearProjectError();
			}
			return result;
		}

