		public static bool ValidAsTextBox(ref DataRow oDr, AsTextBox txt, string whereCondition, string sFieldList = "", bool aTried2Lookup = false)
		{
			//IL_00a8: Unknown result type (might be due to invalid IL or missing references)
			oDr = null;
			if ((Operators.CompareString(((TextBox)txt).Text, "", false) == 0 || txt.Code_FName == null || Operators.CompareString(txt.Code_FName, "", false) == 0) ? true : false)
			{
				return true;
			}
			string code_name = Environment.GetLookupInformation(txt.LookupCodeName).code_name;
			if (!ValidMa(ref oDr, code_name, ((TextBox)txt).Text, whereCondition, sFieldList, txt.SD))
			{
				if (!Environment.GetDictionaryInformation(code_name).lookup_when_invalid || (aTried2Lookup ? true : false))
				{
					if (!aTried2Lookup)
					{
						CMessageBox.Show(50001);
					}
					else
					{
						((TextBox)txt).Text = "";
					}
					return false;
				}
				DataRow dataRow = null;
				txt.HidePopup();
				dataRow = Lookup(txt.LookupCodeName, ((TextBox)txt).Text, whereCondition, txt.SD);
				if ((dataRow != null && dataRow.Table.Columns.Contains(txt.Code_FName)) ? true : false)
				{
					((TextBox)txt).Text = Conversions.ToString(dataRow[txt.Code_FName]);
					return ValidAsTextBox(ref oDr, txt, whereCondition, sFieldList, aTried2Lookup: true);
				}
				return false;
			}
			txt.HidePopup();
			return true;
		}

