		public static bool ValidatingAsTextBoxCell(DataGridViewAsTextBoxCell txt, ref string sValue, string sCode_Name, DataRow oDr, bool aTried2Lookup = false)
		{
			//IL_00d3: Unknown result type (might be due to invalid IL or missing references)
			//IL_0103: Unknown result type (might be due to invalid IL or missing references)
			if (Conversions.ToBoolean(Operators.OrObject(Operators.CompareObjectEqual(Helper.Repl_Null(sValue, isNum: false), (object)"", false), (object)(Operators.CompareString(sCode_Name, "", false) == 0))))
			{
				return true;
			}
			string text = txt.LookupWhereCondition;
			if ((Operators.CompareString(text.Trim(), string.Empty, false) != 0 && text.Contains("[")) ? true : false)
			{
				text = DeMacroFromDataRow(text, oDr);
			}
			DataRow pDrw = null;
			if (!ValidMa(ref pDrw, sCode_Name, sValue, text, "", txt.SD))
			{
				if (aTried2Lookup)
				{
					return false;
				}
				if (!Environment.GetDictionaryInformation(sCode_Name).lookup_when_invalid)
				{
					CMessageBox.Show(50001);
					return false;
				}
				LookupInformation lookupInformation = Environment.GetLookupInformation(txt.LookupCodeName);
				if (lookupInformation == null)
				{
					CMessageBox.Show(50001);
					return false;
				}
				string dictionary = lookupInformation.Dictionary;
				DataRow dataRow = null;
				string text2 = dictionary;
				if (Operators.CompareString(text2, "1", false) == 0)
				{
					dataRow = Lookup(txt.LookupCodeName, sValue, text, txt.SD);
				}
				else if (Operators.CompareString(text2, "2", false) == 0)
				{
					dataRow = LookupComplex(txt.LookupCodeName, sValue, text, txt.SD);
				}
				if ((dataRow != null && dataRow.Table.Columns.Contains(txt.Code_FName)) ? true : false)
				{
					sValue = Conversions.ToString(dataRow[txt.Code_FName]);
					return ValidatingAsTextBoxCell(txt, ref sValue, sCode_Name, oDr, aTried2Lookup: true);
				}
				return false;
			}
			return true;
		}

