			if (Operators.CompareString(dAOType, "MsSql", false) == 0)
			{
				return CreateSQLConnectionString(IsSysConnection);
			}
			return CreateSQLConnectionString(IsSysConnection);
		}

		public static string CreateSQLConnectionString(bool IsSysConnection = false)
		{
			string text = ((!IsSysConnection) ? DatabaseConfigurations.DATADatabaseName : DatabaseConfigurations.SYSDatabaseName);
			string authenticationType = DatabaseConfigurations.AuthenticationType;
			if (Operators.CompareString(authenticationType, "WIN", false) == 0)
			{
				return $"Server={DatabaseConfigurations.ServerName};Database={text};Integrated Security=Yes";
			}
			return $"Server={DatabaseConfigurations.ServerName};Uid={DatabaseConfigurations.UserID};Pwd={DatabaseConfigurations.Password};Database={text};Integrated Security=no";
		}
