		private bool ValidData(DataColumn aCol, string aOp, string aPar1, string aPar2)
		{
			if (FilterUtils.IsNumberType(aCol.DataType))
			{
				return Versioned.IsNumeric((object)aPar1) & (Versioned.IsNumeric((object)aPar2) | (Operators.CompareString(aPar2.Trim(), (string)null, false) == 0));
			}
			if (FilterUtils.IsDateTimeType(aCol.DataType))
			{
				return Information.IsDate((object)aPar1) & (Information.IsDate((object)aPar2) | (Operators.CompareString(aPar2.Trim(), (string)null, false) == 0));
			}
			if (FilterUtils.IsDateTimeType(aCol.DataType))
			{
				return Information.IsDate((object)aPar1) & (Information.IsDate((object)aPar2) | (Operators.CompareString(aPar2.Trim(), (string)null, false) == 0));
			}
			return true;
		}

