		private object[] GetFilterOperators(DataColumn column)
		{
			Type dataType = column.DataType;
			ArrayList arrayList = new ArrayList();
			if (FilterUtils.IsBooleanType(dataType))
			{
				arrayList.Add(YES);
				arrayList.Add(NO);
			}
			else if (FilterUtils.IsNumberType(dataType))
			{
				arrayList.Add(GREATER_THAN);
				arrayList.Add(GREATER_THAN_OR_EQUAL);
				arrayList.Add(LESS_THAN);
				arrayList.Add(LESS_THAN_OR_EQUAL);
				arrayList.Add(BETWEEN);
				arrayList.Add(NOT_BETWEEN);
				arrayList.Add(EQUAL);
				arrayList.Add(NOT_EQUAL);
			}
			else if (FilterUtils.IsStringType(dataType))
			{
				arrayList.Add(CONTAIN);
				arrayList.Add(START_WITH);
				arrayList.Add(NOT_CONTAIN);
				arrayList.Add(EQUAL);
				arrayList.Add(NOT_EQUAL);
				arrayList.Add(END_WITH);
			}
			else if (FilterUtils.IsDateTimeType(dataType))
			{
				arrayList.Add(BETWEEN);
				arrayList.Add(GREATER_THAN);
				arrayList.Add(GREATER_THAN_OR_EQUAL);
				arrayList.Add(LESS_THAN);
				arrayList.Add(LESS_THAN_OR_EQUAL);
				arrayList.Add(NOT_BETWEEN);
				arrayList.Add(EQUAL);
				arrayList.Add(NOT_EQUAL);
			}
			return arrayList.ToArray();
		}

		private string Get_Operator(string aOperator, DataColumn aColName, string aOperation1, string aOperation2)
		{
			if (Operators.CompareString(aOperator, YES, false) == 0)
			{
				return aColName.ColumnName + " = True";
			}
			if (Operators.CompareString(aOperator, NO, false) == 0)
			{
				return aColName.ColumnName + " =False";
			}
			if (Operators.CompareString(aOperator, EQUAL, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return aColName.ColumnName + " = " + aOperation1;
				}
				return aColName.ColumnName + " = '" + aOperation1 + "'";
			}
			if (Operators.CompareString(aOperator, NOT_EQUAL, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return aColName.ColumnName + " <> " + aOperation1;
				}
				return aColName.ColumnName + " <> '" + aOperation1 + "'";
			}
			if (Operators.CompareString(aOperator, GREATER_THAN, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return aColName.ColumnName + " > " + aOperation1;
				}
				return aColName.ColumnName + " > '" + aOperation1 + "'";
			}
			if (Operators.CompareString(aOperator, GREATER_THAN_OR_EQUAL, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return aColName.ColumnName + " >= " + aOperation1;
				}
				return aColName.ColumnName + " >= '" + aOperation1 + "'";
			}
			if (Operators.CompareString(aOperator, LESS_THAN, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return aColName.ColumnName + " < " + aOperation1;
				}
				return aColName.ColumnName + " < '" + aOperation1 + "'";
			}
			if (Operators.CompareString(aOperator, LESS_THAN_OR_EQUAL, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return aColName.ColumnName + " <= " + aOperation1;
				}
				return aColName.ColumnName + " <= '" + aOperation1 + "'";
			}
			if (Operators.CompareString(aOperator, BETWEEN, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return "(" + aColName.ColumnName + " >= " + aOperation1 + " AND " + aColName.ColumnName + " <= " + aOperation2 + ")";
				}
				return "(" + aColName.ColumnName + " >= '" + aOperation1 + "' AND " + aColName.ColumnName + " <= '" + aOperation2 + "')";
			}
			if (Operators.CompareString(aOperator, NOT_BETWEEN, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return "(" + aColName.ColumnName + " < " + aOperation1 + " OR " + aColName.ColumnName + " > " + aOperation2 + ")";
				}
				return "(" + aColName.ColumnName + " < '" + aOperation1 + "' OR " + aColName.ColumnName + " > '" + aOperation2 + "')";
			}
			if (Operators.CompareString(aOperator, CONTAIN, false) == 0)
			{
				return aColName.ColumnName + " LIKE '%" + aOperation1.Trim() + "%'";
			}
			if (Operators.CompareString(aOperator, NOT_CONTAIN, false) == 0)
			{
				return aColName.ColumnName + " NOT LIKE '%" + aOperation1.Trim() + "%'";
			}
			if (Operators.CompareString(aOperator, START_WITH, false) == 0)
			{
				return aColName.ColumnName + " LIKE '" + aOperation1.Trim() + "%'";
			}
			if (Operators.CompareString(aOperator, END_WITH, false) == 0)
			{
				return aColName.ColumnName + " LIKE '%" + aOperation1.Trim() + "'";
			}
			if (Operators.CompareString(aOperator, INLIST, false) == 0)
			{
				if (FilterUtils.IsNumberType(aColName.DataType))
				{
					return aColName.ColumnName + " IN (" + aOperation1 + ")";
				}
				return aColName.ColumnName + " IN (" + aOperation1 + ")";
			}
			if (Operators.CompareString(aOperator, ISNULL, false) == 0)
			{
				return aColName.ColumnName + " IS Null";
			}
			return "";
		}

		private void RefreshFilters(ref DataView tableView)
		{
			string text = "";
			if (Operators.CompareString(OrgRowFilter, "", false) != 0)
			{
				text = OrgRowFilter;
			}
			foreach (ColumnFilter value in htColumnFilter.Values)
			{
				if (value.activate)
				{
					text = ((Operators.CompareString(text, "", false) != 0) ? (text + " AND " + value.filter) : (text + value.filter));
				}
			}
			tableView.RowFilter = text;
		}

