		private void cbFilter_SelectedIndexChanged(object sender, EventArgs e)
		{
			((Control)txtExpression1).Enabled = true;
			((Control)txtExpression2).Enabled = false;
			((Control)txtText1).Enabled = true;
			((Control)txtText2).Enabled = false;
			((Control)mnrNumber1).Enabled = true;
			((Control)mnrNumber2).Enabled = false;
			string text = Conversions.ToString(cbFilter.SelectedItem);
			if (Operators.CompareString(text, BETWEEN, false) == 0)
			{
				((Control)txtExpression2).Enabled = true;
				((Control)txtText2).Enabled = true;
				((Control)mnrNumber2).Enabled = true;
			}
			else if (Operators.CompareString(text, NOT_BETWEEN, false) == 0)
			{
				((Control)txtExpression2).Enabled = true;
				((Control)txtText2).Enabled = true;
				((Control)mnrNumber2).Enabled = true;
			}
			else if (Operators.CompareString(text, YES, false) == 0)
			{
				((Control)txtExpression1).Enabled = false;
				((Control)txtText1).Enabled = false;
				((Control)mnrNumber2).Enabled = false;
			}
			else if (Operators.CompareString(text, NO, false) == 0)
			{
				((Control)txtExpression1).Enabled = false;
				((Control)txtText1).Enabled = false;
				((Control)mnrNumber2).Enabled = false;
			}
			((Control)btOK).Enabled = true;
			string text2 = f_strColumnDataType;
			if (Operators.CompareString(text2, "DATETIME", false) == 0)
			{
				((Control)txtExpression1).Focus();
				((Control)txtExpression1).Select();
			}
			else if (Operators.CompareString(text2, "DECIMAL", false) == 0)
			{
				((Control)mnrNumber1).Focus();
				((Control)mnrNumber1).Select();
			}
			else
			{
				((Control)txtText1).Focus();
				((Control)txtText1).Select();
			}
		}

