		private void SearchForm_Load(object sender, EventArgs e)
		{
			string text = Clipboard.GetText();
			_datasource = Environment.GetSearchDatasource();
			cboValue.Text = Clipboard.GetText();
			Clipboard.Clear();
			cboValue.DataSource = _datasource;
			cboScope.SelectedIndex = 0;
			if (((DataGridView)_myDgv).CurrentCell == null)
			{
				MyColumnScopeEnabled = false;
			}
			else
			{
				_findColIndex = ((DataGridView)_myDgv).CurrentCell.ColumnIndex;
			}
		}

		private void btOK_Click(object sender, EventArgs e)
		{
			if (Operators.CompareString(cboValue.Text, "", false) != 0)
			{
				if (_datasource.Contains(cboValue.Text))
				{
					_datasource.Remove(cboValue.Text);
				}
				_datasource.Insert(0, cboValue.Text);
				if (MyScope)
				{
					_findColIndex = ((DataGridView)_myDgv).CurrentCell.ColumnIndex;
					SearchOneColumn(cboValue.Text, _findColIndex, chkWrapAround.Checked, optNewSearch.Checked, isNested: false);
				}
				else
				{
					SearchAllColumn(cboValue.Text, chkWrapAround.Checked, optNewSearch.Checked);
				}
				_sLastFindWhat = cboValue.Text;
				if (!_isFound)
				{
					lbInfo.Text = Helper.GetMessContent(50114);
				}
				else
				{
					lbInfo.Text = string.Format(Helper.GetMessContent(50113), checked(_iLastFoundRowIndex + 1), ((DataGridView)_myDgv).Columns[_iLastFoundColIndex].HeaderText);
				}
			}
		}

