	private void frmUpdVoucherLangResX_Load(object sender, EventArgs e)
	{
		if (Operators.CompareString(f_sDllFullName, "AsiaErp.Framework.frmVoucherView", false) == 0)
		{
			VoucherInformation myVoucherInfo = ((frmVoucherView)(object)f_container).MyVoucherInfo;
			f_sDllFullName += myVoucherInfo.voucher_code;
		}
		GetAllControl((Control)(object)f_container, f_hstControl);
		InitControlInfoTable();
		LoadControlInfo(f_hstControl);
		if (Operators.CompareString(f_UserControlName, string.Empty, false) == 0)
		{
			((DataGridViewColumn)UserControlName).Visible = false;
		}
		else
		{
			LoadControlInfo(f_hstControlofUserControl, f_UserControlName);
		}
		LoadLangInfoDB();
		f_dvControl = f_oTblControl.DefaultView;
		f_dvControl.Sort = "parentControl,Y,X,STT";
		((DataGridView)dgvUpdLangResX).DataSource = f_dvControl;
		((DataGridView)dgvUpdLangResX).BackgroundColor = ClientConfiguration.DM_BakgroundColor;
		((DataGridView)dgvUpdLangResX).AlternatingRowsDefaultCellStyle.BackColor = ClientConfiguration.DM_AlternatingBackColor;
		LoadCombo();
	}

	private void cmdOK_Click(object sender, EventArgs e)
	{
		foreach (DataRow row in f_oTblControl.Rows)
		{
			ArrayList arrayList = new ArrayList();
			arrayList.Add(f_sDllFullName);
			arrayList.Add(RuntimeHelpers.GetObjectValue(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(row["UserControlName"]), isNum: false)));
			arrayList.Add(RuntimeHelpers.GetObjectValue(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(row["controlName"]), isNum: false)));
			arrayList.Add(RuntimeHelpers.GetObjectValue(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(row["propertyName"]), isNum: false)));
			arrayList.Add(RuntimeHelpers.GetObjectValue(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(row["formula"]), isNum: false)));
			arrayList.Add(RuntimeHelpers.GetObjectValue(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(row["defaultValue"]), isNum: false)));
			arrayList.Add(RuntimeHelpers.GetObjectValue(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(row["propertyValue"]), isNum: false)));
			arrayList.Add(SystemInformations.CurrentCultureName);
			Commons.ExecuteSYSDBStoredProcedure("asUpdLangTranslationResx", arrayList.ToArray());
		}
		if ((object)((object)f_container).GetType().BaseType == typeof(frmReport))
		{
			UpdReportResX();
		}
		if ((object)((object)f_container).GetType().BaseType == typeof(frmReport2DGV))
		{
			UpdReport2DGVResX();
		}
		if ((object)((object)f_container).GetType().BaseType == typeof(frmDMView))
		{
			UpdDMResX();
		}
		if ((object)((object)f_container).GetType().BaseType == typeof(frmOBView))
		{
			UpdOBResX();
		}
		if ((object)((object)f_container).GetType().BaseType == typeof(frmDMComplexView))
		{
			UpdDMComplexResX();
		}
		if ((object)((object)f_container).GetType() == typeof(frmLookup))
		{
			UpdLookupResX();
		}
		if ((object)((object)f_container).GetType() == typeof(frmLookupComplex))
		{
			UpdLookupComplexResX();
		}
		if ((object)((object)f_container).GetType() == typeof(frmVoucherView))
		{
			UpdVoucherResx();
		}
		((Form)this).Close();
	}

