		[DebuggerNonUserCode]
		public ClientConfiguration()
		{
		}

		public static void LoadConfig()
		{
			if (_isLoaded)
			{
				return;
			}
			_isLoaded = true;
			NameValueCollection appSettings = ConfigurationManager.AppSettings;
			string[] allKeys = appSettings.AllKeys;
			_show_button = appSettings["SHOW_BUTTON"];
			_bMulti_lang_enabled = appSettings["MUTI_LANG_ENABLED"];
			if (allKeys.Contains("MA_CT_TAIN"))
			{
				_sMa_ct_TaIn = appSettings["MA_CT_TAIN"];
			}
			if (allKeys.Contains("MA_CT_TAOUT"))
			{
				_sMa_ct_TaOut = appSettings["MA_CT_TAOUT"];
			}
			_sField2CarryInReport = appSettings["Field2CarryInReport"];
			if (allKeys.Contains("EscapeCharacters"))
			{
				_sEscapeCharacters = appSettings["EscapeCharacters"];
			}
			checked
			{
				if (allKeys.Contains("AUTO_INSERT_DETAIL_OF_VOUCHER_WARNING_LEVEL"))
				{
					string? s = appSettings["AUTO_INSERT_DETAIL_OF_VOUCHER_WARNING_LEVEL"];
					int result = (int)_auto_insert_detail_of_voucher_warning;
					int.TryParse(s, out result);
					_auto_insert_detail_of_voucher_warning = (uint)result;
				}
				if (allKeys.Contains("LOGTYPE"))
				{
					_LogType = appSettings["LOGTYPE"];
				}
				if (allKeys.Contains("MAX_WIDTH_OF_COLUMN_REPORT"))
				{
					int.TryParse(appSettings["MAX_WIDTH_OF_COLUMN_REPORT"], out _max_report_column_with);
					if (_max_report_column_with <= 0)
					{
						_max_report_column_with = 300;
					}
				}
				if (allKeys.Contains("Name_Help"))
				{
					_Name_Help = appSettings["Name_Help"];
				}
				if (allKeys.Contains("Them"))
				{
					_Theme = appSettings["Theme"];
				}
				try
				{
					_DEFAULT_FORM_BACKCOLOR = ColorFromConfig(appSettings["FORM_BACKGROUND_COLOR"]);
				}
				catch (Exception ex)
				{
					ProjectData.SetProjectError(ex);
					Exception ex2 = ex;
					ProjectData.ClearProjectError();
				}
			}
		}

		private static Color ColorFromConfig(string sValue)
		{
			sValue = sValue.Trim();
			Color result = Color.Black;
			if (sValue.ToLower().Contains("rgb"))
			{
				int num = sValue.IndexOf("(");
				int num2 = sValue.IndexOf(")");
				string[] array = checked(sValue.Substring(num + 1, num2 - num - 1)).Split(new char[1] { ',' });
				try
				{
					result = Color.FromArgb(Conversions.ToInteger(array[0]), Conversions.ToInteger(array[1]), Conversions.ToInteger(array[2]));
				}
				catch (Exception ex)
				{
					ProjectData.SetProjectError(ex);
					Exception ex2 = ex;
					ProjectData.ClearProjectError();
				}
			}
			else
			{
				try
				{
					result = Color.FromName(sValue);
				}
				catch (Exception ex3)
				{
					ProjectData.SetProjectError(ex3);
					Exception ex4 = ex3;
					ProjectData.ClearProjectError();
				}
			}
			return result;
		}
	}
