	[StandardModule]
	[HideModuleName]
	public sealed class Theme
	{
		private static Hashtable _hstTheme;

		private const string DEFAULT_THEME = "Default";

		public static Hashtable GetThemeConfiguration()
		{
			//IL_0022: Unknown result type (might be due to invalid IL or missing references)
			//IL_0028: Expected O, but got Unknown
			//IL_005e: Unknown result type (might be due to invalid IL or missing references)
			//IL_0065: Expected O, but got Unknown
			if (_hstTheme == null)
			{
				_hstTheme = new Hashtable();
				DataSet dataSet = new DataSet();
				XmlDocument val = new XmlDocument();
				string path = SystemInformations.XMLPath + "/Theme.xml";
				if (File.Exists(path))
				{
					val.Load(SystemInformations.XMLPath + "/Theme.xml");
					XmlNodeReader reader = new XmlNodeReader((XmlNode)(object)val);
					dataSet.ReadXml((XmlReader?)(object)reader);
					string text = "";
					text = ClientConfiguration.Theme;
					System.Data.DataTable dataTable = dataSet.Tables[text];
					foreach (DataColumn column in dataTable.Columns)
					{
						_hstTheme.Add(column.ColumnName, RuntimeHelpers.GetObjectValue(dataTable.Rows[0][column.ColumnName]));
					}
				}
			}
			return _hstTheme;
		}
	}
