				{
					return null;
				}
				aVarName = aVarName.Trim().ToUpper();
				object result = null;
				if (_hstPublicVariable == null)
				{
					_hstPublicVariable = new Hashtable();
				}
				if (_hstPublicVariable.ContainsKey(aVarName))
				{
					result = RuntimeHelpers.GetObjectValue(_hstPublicVariable[aVarName]);
				}
				return result;
			}
			set
			{
				if (!Operators.ConditionalCompareObjectEqual(Helper.Repl_Null(aVarName, isNum: false), (object)"", false))
				{
					aVarName = aVarName.Trim().ToUpper();
					if (_hstPublicVariable == null)
					{
						_hstPublicVariable = new Hashtable();
					}
					if (_hstPublicVariable.ContainsKey(aVarName))
					{
						_hstPublicVariable[aVarName] = RuntimeHelpers.GetObjectValue(value);
					}
					else
					{
						_hstPublicVariable.Add(aVarName, RuntimeHelpers.GetObjectValue(value));
					}
				}
			}
		}

