		public static System.Data.DataTable GetDictionary(string pCodeName, string pCodeValue, string sWhereClause, string pField_List, string pTable_name)
		{
			if (_hstDictionary == null)
			{
				_hstDictionary = new Hashtable();
			}
			string key = pCodeName + "ASIASOFT" + sWhereClause;
			CommonDAO commonDAO = (CommonDAO)DAOFactory.CreateDAOInstance("CommonDAO", "Framework");
			System.Data.DataTable dataTable;
			if (_hstDictionary.ContainsKey(key))
			{
				Cacheable cacheable = (Cacheable)_hstDictionary[key];
				dataTable = (System.Data.DataTable)cacheable.Value;
				DateTime pLastModDate = cacheable.Last_Modified_Date;
				System.Data.DataTable dataTable2 = commonDAO.Lookup(CompanyInformations.CompanyID, pCodeName, pField_List, pTable_name, sWhereClause, ref pLastModDate);
				cacheable.Last_Modified_Date = pLastModDate;
				dataTable.PrimaryKey = new DataColumn[1] { dataTable.Columns[pCodeName] };
				foreach (DataRow row in dataTable2.Rows)
				{
					object[] array = new object[1] { RuntimeHelpers.GetObjectValue(row[pCodeName]) };
					dataTable.Rows.Find(RuntimeHelpers.GetObjectValue(row[pCodeName]))?.Delete();
					dataTable.Rows.Add(row);
				}
				dataTable.PrimaryKey = null;
			}
			else
			{
				DateTime pLastModDate = new DateTime(1900, 1, 1);
				dataTable = commonDAO.Lookup(CompanyInformations.CompanyID, pCodeName, pField_List, pTable_name, sWhereClause, ref pLastModDate);
				Cacheable cacheable = new Cacheable(pLastModDate, dataTable);
				_hstDictionary.Add(key, cacheable);
			}
			commonDAO.Destroy();
			return dataTable;
		}

