		public static void RefreshConfiguration(string ModuleID)
		{
			if (Operators.CompareString(ModuleID.Trim(), "", false) != 0)
			{
				switch (ModuleID)
				{
				case "SI":
					_SIConfiguration = null;
					GetSIConfiguration();
					break;
				case "SO":
					_SOConfiguration = null;
					GetSOConfiguration();
					break;
				case "PO":
					_POConfiguration = null;
					GetPOConfiguration();
					break;
				case "IN":
					_INConfiguration = null;
					GetINConfiguration();
					break;
				case "FA":
					_FAConfiguration = null;
					GetFAConfiguration();
					break;
				case "SIDMNT":
					_arlDMNT = null;
					GetDMNT();
					break;
				}
			}
		}

