	public class Cacheable
	{
		private DateTime _last_mod_date;

		private object _value;

		public DateTime Last_Modified_Date
		{
			get
			{
				return _last_mod_date;
			}
			set
			{
				_last_mod_date = value;
			}
		}

		public object Value
		{
			get
			{
				return _value;
			}
			set
			{
				_value = RuntimeHelpers.GetObjectValue(value);
			}
		}

		public Cacheable()
		{
			_last_mod_date = DateAndTime.Now;
		}

		public Cacheable(DateTime lastModDate, object val)
		{
			_last_mod_date = lastModDate;
			_value = RuntimeHelpers.GetObjectValue(val);
		}
	}
