		public object Execute(params object[] ParamValues)
		{
			return (int)f_oCalInfo.rettype switch
			{
				0 => MyDAO.ExecuteNoneQuery(f_oCalInfo.spname, ParamValues), 
				2 => MyDAO.ExecuteQueryTable(f_oCalInfo.spname, ParamValues), 
				1 => MyDAO.ExecuteQueryScalar(f_oCalInfo.spname, ParamValues), 
				_ => MyDAO.ExecuteNoneQuery(f_oCalInfo.spname, ParamValues), 
			};
		}

