		private void frmDoima_Load(object sender, EventArgs e)
		{
			txtOldCode.Text = Conversions.ToString(f_oDrwEdit[f_oMyDictInfo.code_fname]);
			txtNewCode.Text = Conversions.ToString(f_oDrwEdit[f_oMyDictInfo.code_fname]);
			((TextBoxBase)txtNewCode).MaxLength = f_oMyDictInfo.code_length;
			((Control)txtNewCode).Select();
		}

		private void cmdOK_Click(object sender, EventArgs e)
		{
			//IL_00cc: Unknown result type (might be due to invalid IL or missing references)
			//IL_0172: Unknown result type (might be due to invalid IL or missing references)
			//IL_0178: Invalid comparison between Unknown and I4
			//IL_0137: Unknown result type (might be due to invalid IL or missing references)
			if (Operators.CompareString(txtNewCode.Text.Trim().ToUpper(), txtOldCode.Text.Trim().ToUpper(), false) == 0)
			{
				((Form)this).Close();
				return;
			}
			if (!MyController.ChkCodeExist(txtNewCode.Text.Trim()))
			{
				if (!ChangeCode())
				{
					return;
				}
				f_oDrwEdit[f_oMyDictInfo.code_fname] = txtNewCode.Text.Trim().ToUpper();
				f_blnOk = true;
			}
			else
			{
				if (!f_oMyDictInfo.allow_merge_code)
				{
					CMessageBox.Show(50107);
					return;
				}
				if (MyController.ChkCodeExistBeforeChange(txtOldCode.Text.Trim(), txtNewCode.Text.Trim()))
				{
					if (!MyController.ChkCodeExistBeforeChange("", txtNewCode.Text.Trim()))
					{
						CMessageBox.Show(50011);
						return;
					}
					if ((int)CMessageBox.ShowWithFormat(50108, (MessageBoxButtons)4, txtNewCode.Text, txtOldCode.Text) == 6)
					{
						if (!ChangeCode())
						{
							return;
						}
						f_oDrwEdit.Delete();
						f_blnOk = true;
					}
				}
				else
				{
					if (!ChangeCode())
					{
						return;
					}
					f_oDrwEdit[f_oMyDictInfo.code_fname] = txtNewCode.Text.Trim().ToUpper();
					f_blnOk = true;
				}
			}
			((Form)this).Close();
		}

		private void cmdCancel_Click(object sender, EventArgs e)
		{
			((Form)this).Close();
		}

		private bool ChangeCode()
		{
			return MyController.ChangeCode(txtOldCode.Text.Trim(), txtNewCode.Text.Trim());
		}

