				}
				text = MyDictInfo.code_fname + " like '";
			}
			else
			{
				text = MyDictInfo.name_fname + " like '";
			}
			if (Conversions.ToDouble(f_oLookupInfor.filter_operator) == 1.0)
			{
				text += "%";
			}
