			try
			{
				array = f_oTblDM.Select(text);
			}
			catch (Exception ex)
			{
				ProjectData.SetProjectError(ex);
				Exception ex2 = ex;
				Helper.ProcessError(ex2);
				ProjectData.ClearProjectError();
			}
