				while (true)
				{
					int num4 = num3;
					int num5 = num2;
					if (num4 > num5)
					{
						break;
					}
					if (Array.IndexOf(array, f_oTblDM.DefaultView[num3].Row) != -1)
					{
						((DataGridView)adgvDM).CurrentCell = ((DataGridView)adgvDM).Rows[num3].Cells[MyDictInfo.code_fname];
						f_intStart = num3 + 1;
						if (f_intStart == f_oTblDM.DefaultView.Count)
