		private int LoadPage(int rowIndex)
		{
			int pRowCount = 0;
			int num = 1;
			checked
			{
				num = (int)Math.Round(Conversion.Int((double)rowIndex / 101.0) + 1.0);
				if (rowIndex < lastRetrieveIndex)
				{
					return 0;
				}
				CommonDAO commonDAO = (CommonDAO)DAOFactory.CreateDAOInstance("CommonDAO", "Framework");
				string companyID = CompanyInformations.CompanyID;
				string code_name = f_oLookupInfor.code_name;
				string field_List = f_oLookupInfor.Field_List;
				string table_name = f_oDictInfo.table_name;
				string pWhere = f_sWhere;
				int pPageNumber = num;
				DateTime pLastModDate = DateAndTime.Now;
				System.Data.DataTable dataTable = commonDAO.PagingLookup(companyID, code_name, field_List, table_name, pWhere, pPageNumber, 100, ref pRowCount, ref pLastModDate);
				commonDAO.Destroy();
				if (f_oTblDM != null)
				{
					foreach (object row in dataTable.Rows)
					{
						object objectValue = RuntimeHelpers.GetObjectValue(row);
						f_oTblDM.ImportRow((DataRow)objectValue);
					}
				}
				else
				{
					f_oTblDM = dataTable;
				}
				lastRetrieveIndex += 100;
				return pRowCount;
			}
		}
