		private string ConvertDGV2InputMask(string sDGVFormat)
		{
			sDGVFormat = Conversions.ToString(Helper.Repl_Null(sDGVFormat, isNum: false));
			string result = sDGVFormat.Trim();
			SIConfiguration sIConfiguration = Environment.GetSIConfiguration();
			string text = sDGVFormat.Trim();
			if (Operators.CompareString(text, sIConfiguration.Amount_Input_Format, false) == 0)
			{
				result = "OA";
			}
			else if (Operators.CompareString(text, sIConfiguration.FCAmount_Input_Format, false) == 0)
			{
				result = "FA";
			}
			else if (Operators.CompareString(text, sIConfiguration.Qty_Input_Format, false) == 0)
			{
				result = "QT";
			}
			else if (Operators.CompareString(text, sIConfiguration.Price_Input_Format, false) == 0)
			{
				result = "OP";
			}
			else if (Operators.CompareString(text, sIConfiguration.FCPrice_Input_Format, false) == 0)
			{
				result = "FP";
			}
			return result;
		}

		private void UpdateResX()
		{
			string text = "";
			DataView defaultView = f_oTblFilter.DefaultView;
			defaultView.RowFilter = "sel=true";
			foreach (DataRowView item in defaultView)
			{
				text = Conversions.ToString(Operators.AddObject((object)text, item["Field_Name"]));
				if ((Operators.ConditionalCompareObjectNotEqual(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(item["Header"]), isNum: false), (object)"", false) && Operators.ConditionalCompareObjectNotEqual(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(item["Header"]), isNum: false), item["Field_Name"], false)) ? true : false)
				{
					text = text + ":H=" + Helper.Repl_Null(RuntimeHelpers.GetObjectValue(item["Header"]), isNum: false).ToString().Trim();
				}
				if (Operators.ConditionalCompareObjectNotEqual(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(item["Format"]), isNum: false), (object)"", false))
				{
					text = text + ":F=" + Helper.Repl_Null(RuntimeHelpers.GetObjectValue(item["Format"]), isNum: false).ToString().Trim();
				}
				if (Operators.ConditionalCompareObjectGreater(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(item["width"]), isNum: true), (object)0, false))
				{
					text = text + ":W=" + Helper.Repl_Null(RuntimeHelpers.GetObjectValue(item["width"]), isNum: true).ToString().Trim();
				}
				if (Operators.ConditionalCompareObjectEqual(Helper.Repl_Null(RuntimeHelpers.GetObjectValue(item["isReadOnly"]), isNum: false), (object)"false", false))
				{
					text += ":E";
				}
				text += ",";
			}
			text = text.Substring(0, checked(text.Length - 1));
			Commons.ExecuteSYSDBStoredProcedure("asUpdateLookupResX", f_LookupInfo.code_name, SystemInformations.CurrentCultureName, text);
			f_LookupInfo.formated_col_list = text;
			Commons.DictionaryDGVFormat(f_dgvDM, f_oTblView, text);
		}

