		protected virtual void ApplySysMessage(System.Data.DataTable tbl)
		{
			if ((Operators.CompareString(MyReportInfo.description_colname.Trim(), "", false) == 0 || tbl == null || !tbl.Columns.Contains(MyReportInfo.description_colname) || !tbl.Columns.Contains("has_sysmsg")) ? true : false)
			{
				return;
			}
			Dictionary<string, LangSysMessageResx> langSysMessageResX = Environment.getLangSysMessageResX();
			string text = "";
			string text2 = "";
			int num = 0;
			checked
			{
				if (tbl.Columns.Contains("has_sysmsg"))
				{
					DataRow[] array = tbl.Select("has_sysmsg='1'");
					DataRow[] array2 = array;
					foreach (DataRow dataRow in array2)
					{
						string[] array3 = dataRow[MyReportInfo.description_colname].ToString().Split(new char[1] { ';' });
						if (array3.Length <= 0)
						{
							continue;
						}
						num = array3[0].IndexOf("#");
						if (num < 0)
						{
							continue;
						}
						text2 = array3[0].Substring(num).Trim();
						if (!langSysMessageResX.ContainsKey(text2))
						{
							continue;
						}
						text = array3[0].Replace(text2, langSysMessageResX[text2].value);
						if (array3.Length > 1)
						{
							string[] array4 = array3[1].Split(new char[1] { ',' });
							int num2 = array4.Length - 1;
							int num3 = 0;
							while (true)
							{
								int num4 = num3;
								int num5 = num2;
								if (num4 > num5)
								{
									break;
								}
								text = string.Format(text, array4[num3]);
								num3++;
							}
						}
						dataRow[MyReportInfo.description_colname] = text;
					}
					return;
				}
				foreach (string key in langSysMessageResX.Keys)
				{
					DataRow[] array = tbl.Select(MyReportInfo.description_colname + " like '" + key + "%'");
					DataRow[] array5 = array;
					foreach (DataRow dataRow2 in array5)
					{
						string[] array3 = dataRow2[MyReportInfo.description_colname].ToString().Split(new char[1] { ';' });
						if (array3.Length <= 0)
						{
							continue;
						}
						num = array3[0].IndexOf("#");
						if (num < 0)
						{
							continue;
						}
						text2 = array3[0].Substring(num).Trim();
						if (Operators.CompareString(text2, key, false) != 0)
						{
							continue;
						}
						text = array3[0].Replace(text2, langSysMessageResX[text2].value);
						if (array3.Length > 1)
						{
							string[] array4 = array3[1].Split(new char[1] { ',' });
							int num6 = array4.Length - 1;
							int num7 = 0;
							while (true)
							{
								int num8 = num7;
								int num5 = num6;
