		protected virtual void ApplySysMessage(System.Data.DataTable tbl)
		{
			if ((Operators.CompareString(MyReportInfo.description_colname.Trim(), "", false) == 0 || tbl == null || !tbl.Columns.Contains(MyReportInfo.description_colname)) ? true : false)
			{
				return;
			}
			Dictionary<string, LangSysMessageResx> langSysMessageResX = Environment.getLangSysMessageResX();
