		private void frmUpdRptResX_Load(object sender, EventArgs e)
		{
			f_oTblFilter = new System.Data.DataTable("Filter");
			f_oTblFilter.Columns.Add("Field_Name", typeof(string));
			f_oTblFilter.Columns.Add("Header", typeof(string));
			f_oTblFilter.Columns.Add("Format", typeof(string));
			f_oTblFilter.Columns.Add("Numeric", typeof(bool));
			f_oTblFilter.Columns.Add("sel", typeof(bool));
			f_oTblFilter.Columns.Add("width", typeof(decimal));
			f_oTblFilter.Columns.Add("stt", typeof(int));
			DataColumn[] primaryKey = new DataColumn[1] { f_oTblFilter.Columns["Field_Name"] };
			f_oTblFilter.PrimaryKey = primaryKey;
			DataGridViewColumn val = ((DataGridView)f_dgvBC).Columns.GetFirstColumn((DataGridViewElementStates)64);
			int num = 1;
			checked
			{
				while (true)
				{
					DataRow dataRow = f_oTblFilter.NewRow();
					dataRow["Field_Name"] = val.DataPropertyName.ToLower();
					dataRow["Header"] = val.HeaderText;
					dataRow["Format"] = ConvertDGV2InputMask(val.DefaultCellStyle.Format);
					dataRow["width"] = val.Width;
					dataRow["sel"] = true;
					DataColumn dataColumn = f_oTblView.Columns[val.DataPropertyName];
					if (Commons.isNumericType(dataColumn.DataType))
					{
						dataRow["Numeric"] = true;
					}
					else
					{
						dataRow["Numeric"] = false;
					}
					dataRow["stt"] = num;
					num++;
					f_oTblFilter.Rows.Add(dataRow);
					val = ((DataGridView)f_dgvBC).Columns.GetNextColumn(val, (DataGridViewElementStates)64, (DataGridViewElementStates)0);
					if (val == null)
					{
						break;
					}
				}
				foreach (DataColumn column in f_oTblView.Columns)
				{
					if (!f_oTblFilter.Rows.Contains(column.ColumnName))
					{
						DataRow dataRow = f_oTblFilter.NewRow();
						dataRow["Field_Name"] = column.ColumnName.ToLower();
						dataRow["Header"] = column.ColumnName;
						dataRow["Format"] = "";
						dataRow["width"] = column.MaxLength;
						dataRow["sel"] = false;
						if (Commons.isNumericType(column.DataType))
						{
							dataRow["Numeric"] = true;
							dataRow["Format"] = "### ### ###";
						}
						else
						{
							dataRow["Numeric"] = false;
						}
						dataRow["stt"] = num;
						num++;
						f_oTblFilter.Rows.Add(dataRow);
					}
				}
				f_oTblFilter.AcceptChanges();
				f_dvFilter = f_oTblFilter.DefaultView;
				f_dvFilter.Sort = "stt";
				((DataGridView)dgvFilter).DataSource = f_dvFilter;
			}
		}

