				}
				break;
			case 2:
				flag = Conversions.ToBoolean(Update2DB());
				break;
			}
			text = Conversions.ToString(CurrentPHRow["Stt_Rec"]);
			if (flag)
			{
				f_oTblPh.AcceptChanges();
				f_oTblCt.AcceptChanges();
				if ((MyVoucherInfo.has_cp && f_oTblCp != null) ? true : false)
				{
