		private bool InitMauBaocao()
		{
			ArrayList reportInformation = Environment.GetReportInformation(base.MyMenuID);
			if (reportInformation == null || reportInformation.Count == 0)
			{
				return false;
			}
			cboMau_bc.DataSource = reportInformation;
			((ListControl)cboMau_bc).DisplayMember = "ten_mau";
			((ListControl)cboMau_bc).ValueMember = "ma_mau";
			cboMau_bc.SelectedItem = 0;
			txtTieu_De.Text = MyReportInfo.title;
			return true;
		}

		private void SetFomularFields()
		{
			SetExtensionFormulaField();
			MyFomularFields.Add("strTitle", txtTieu_De.Text.Trim());
			MyFomularFields.Add("so_ct_kem", txtSo_Ct_Kem.Text);
			MyVoucherInfo.number_of_copy = Conversions.ToInteger(txtSo_lien.Value);
		}

		protected virtual void SetExtensionFormulaField()
		{
		}

		protected virtual void InitOtherComponent()
		{
		}

		protected virtual void ModifyReport()
		{
			//IL_005e: Unknown result type (might be due to invalid IL or missing references)
			//IL_003c: Unknown result type (might be due to invalid IL or missing references)
			string text = f_sReportPath + MyReportInfo.rptname.Trim();
			if (!File.Exists(text))
			{
				CMessageBox.ShowWithFormat(50110, new object[1] { text });
				return;
			}
			try
			{
				Process.Start(text);
			}
			catch (Exception ex)
			{
				ProjectData.SetProjectError(ex);
				Exception ex2 = ex;
				CMessageBox.Show(ex2.Message);
				ProjectData.ClearProjectError();
			}
		}

		private void frmVoucherPrint_Load(object sender, EventArgs e)
		{
			//IL_006f: Unknown result type (might be due to invalid IL or missing references)
			if (!((Component)(object)this).DesignMode)
			{
				((Form)this).Text = MyVoucherInfo.description;
				txtSo_lien.Value = Environment.GetSiDMCTByMa_Ct(MyVoucherInfo.voucher_code).so_lien;
				if (!InitMauBaocao())
				{
					CMessageBox.ShowWithFormat(50112, new object[1] { MyVoucherInfo.description });
					((Form)this).DialogResult = (DialogResult)2;
					((Form)this).Close();
				}
				InitOtherComponent();
			}
		}

