		private void frmVoucherView_Load(object sender, EventArgs e)
		{
			if (!((Component)(object)this).DesignMode)
			{
				GetLangResX();
				FormatGridView();
				dgvPh.DataSource = bsPH;
				dgvCt.DataSource = bsCT;
				SetStatusBar();
			}
		}

		protected virtual void GetLangResX()
		{
			((Form)this).Text = Environment.getLangFrameworkResX("#BASEVOUCHER_VIEWFORM_TEXT");
			((ToolStripItem)tsmiSelectAll).Text = Environment.getLangFrameworkResX("#BASEVOUCHER_VIEWFORM_SELECTALL_TEXT");
			((ToolStripItem)tsslCountlbl).Text = Environment.getLangFrameworkResX("#BASEVOUCHER_VIEWFORM_VOUCHER_COUNT_TEXT");
			((ToolStripItem)tsslTTtlbl).Text = Environment.getLangFrameworkResX("#BASEVOUCHER_VIEWFORM_VOUCHER_AMOUNT_TEXT");
			((ToolStripItem)tssbIn).Text = Environment.getLangFrameworkResX("#BASEVOUCHER_PRINT_TEXT");
		}

		private void tssbIn_ButtonClick(object sender, EventArgs e)
		{
			//IL_00b8: Unknown result type (might be due to invalid IL or missing references)
			((DataGridView)dgvPh).NotifyCurrentCellDirty(true);
			((DataGridView)dgvPh).CommitEdit((DataGridViewDataErrorContexts)512);
			f_oTblPh.AcceptChanges();
			bool flag = false;
			foreach (DataRowView item in f_oTblPh.DefaultView)
			{
				if (Operators.ConditionalCompareObjectEqual(item["chon"], (object)true, false))
				{
					flag = true;
					break;
				}
			}
			if (flag)
			{
				f_isPrintRequest = true;
				((Form)this).Close();
			}
			else
			{
				CMessageBox.Show(50118);
			}
		}

		private void tsmiSelectAll_Click(object sender, EventArgs e)
		{
			f_isSeletedAll = Operators.NotObject(f_isSeletedAll);
			foreach (DataRowView item in f_oTblPh.DefaultView)
			{
				item["chon"] = RuntimeHelpers.GetObjectValue(f_isSeletedAll);
			}
			((Control)dgvPh).Refresh();
		}

		private void frmVoucherView_KeyDown(object sender, KeyEventArgs e)
		{
			//IL_0002: Unknown result type (might be due to invalid IL or missing references)
			//IL_0009: Invalid comparison between Unknown and I4
			//IL_0018: Unknown result type (might be due to invalid IL or missing references)
			//IL_001f: Invalid comparison between Unknown and I4
			if ((int)e.KeyCode == 27)
			{
				((Form)this).Close();
			}
			if ((int)e.KeyCode == 123)
