				UpdateVchResX();
			}
		}

		protected virtual void FormatGridView()
		{
			if (f_oTblPh != null && f_oTblCt != null && 0 == 0)
			{
				Commons.VoucherDGVFormat(dgvPh, f_oTblPh, MyVoucherInfo.ph_formated_col_list, "colPH");
				Commons.VoucherDGVFormat(dgvCt, f_oTblCt, MyVoucherInfo.ct_formated_col_list, "colCT");
			}
		}

		protected virtual void SetStatusBar()
		{
			((ToolStripItem)tsslCount).Text = Conversions.ToString(f_oTblPh.Rows.Count);
			if ((f_oTblPh.Columns.Contains("T_Tien_Nt") && f_oTblPh.Columns.Contains("T_Tien")) ? true : false)
			{
				ToolStripStatusLabel obj = tsslTTt;
				decimal num = (decimal)f_oTblPh.Compute("sum(T_Tien_Nt)", "");
				string text = num.ToString(Environment.GetSIConfiguration().FCAmount_Input_Format);
				decimal num2 = (decimal)f_oTblPh.Compute("sum(T_Tien)", "");
				((ToolStripItem)obj).Text = text + "/" + num2.ToString(Environment.GetSIConfiguration().Amount_Input_Format);
			}
			if ((f_oTblPh.Columns.Contains("T_Tt_Nt") && f_oTblPh.Columns.Contains("T_Tt")) ? true : false)
			{
				ToolStripStatusLabel obj2 = tsslTTt;
				decimal num2 = (decimal)f_oTblPh.Compute("sum(T_Tt_Nt)", "");
				string text2 = num2.ToString(Environment.GetSIConfiguration().FCAmount_Input_Format);
				decimal num = (decimal)f_oTblPh.Compute("sum(T_Tt)", "");
				((ToolStripItem)obj2).Text = text2 + "/" + num.ToString(Environment.GetSIConfiguration().Amount_Input_Format);
			}
		}

